@@ -0,0 +1,70 @@
+import { describe, expect, test } from "bun:test";
+import { isDisposableEmail, validateEmail } from "./email-validation";
+
+describe("isDisposableEmail", () => {
+  test("rejects known disposable domains", () => {
+    expect(isDisposableEmail("test@mailinator.com")).toBe(true);
+    expect(isDisposableEmail("test@guerrillamail.com")).toBe(true);
+    expect(isDisposableEmail("test@yopmail.com")).toBe(true);
+  });
+
+  test("accepts legitimate domains", () => {
+    expect(isDisposableEmail("test@gmail.com")).toBe(false);
+    expect(isDisposableEmail("test@outlook.com")).toBe(false);
+    expect(isDisposableEmail("test@company.co")).toBe(false);
+  });
+
+  test("is case-insensitive", () => {
+    expect(isDisposableEmail("test@MAILINATOR.COM")).toBe(true);
+    expect(isDisposableEmail("test@Gmail.Com")).toBe(false);
+  });
+
+  test("returns false for input without @", () => {
+    expect(isDisposableEmail("no-at-sign")).toBe(false);
+  });
+});
+
+describe("validateEmail", () => {
+  test("rejects invalid format", async () => {
+    const result = await validateEmail("not-an-email");
+    expect(result.valid).toBe(false);
+    if (!result.valid) {
+      expect(result.reason).toBe("invalid_format");
+    }
+  });
+
+  test("rejects null and undefined", async () => {
+    // @ts-expect-error testing runtime behavior with invalid input
+    expect((await validateEmail(null)).valid).toBe(false);
+    // @ts-expect-error testing runtime behavior with invalid input
+    expect((await validateEmail(undefined)).valid).toBe(false);
+  });
+
+  test("rejects empty string", async () => {
+    const result = await validateEmail("");
+    expect(result.valid).toBe(false);
+    if (!result.valid) {
+      expect(result.reason).toBe("invalid_format");
+    }
+  });
+
+  test("rejects malformed emails that contain @", async () => {
+    expect((await validateEmail("@")).valid).toBe(false);
+    expect((await validateEmail("foo@")).valid).toBe(false);
+    expect((await validateEmail("@bar")).valid).toBe(false);
+    expect((await validateEmail("foo@bar")).valid).toBe(false);
+  });
+
+  test("rejects disposable emails", async () => {
+    const result = await validateEmail("test@mailinator.com");
+    expect(result.valid).toBe(false);
+    if (!result.valid) {
+      expect(result.reason).toBe("disposable");
+    }
+  });
+
+  test("accepts valid email addresses", async () => {
+    const result = await validateEmail("user@example.com");
+    expect(result.valid).toBe(true);
+  });
+});
diff --git a/apps/web/lib/email-validation.ts b/apps/web/lib/email-validation.ts
new file mode 100644
index 0000000..d196fb3
--- /dev/null
+++ b/apps/web/lib/email-validation.ts
@@ -0,0 +1,131 @@
+// Email validation pipeline: format → disposable domain blocklist → Abstract API deliverability.
+// Each layer short-circuits on failure, so expensive checks only run after cheaper ones pass.
+
+import { log } from "@repo/observability/log";
+import disposableDomains from "disposable-email-domains";
+import { z } from "zod";
+
+const disposableSet = new Set(disposableDomains);
+
+const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
+
+export type ValidationFailureReason =
+  | "invalid_format"
+  | "disposable"
+  | "undeliverable";
+
+export type ValidationResult =
+  | { valid: true }
+  | { valid: false; reason: ValidationFailureReason };
+
+const TRUSTED_DOMAINS = new Set([
+  "gmail.com",
+  "googlemail.com",
+  "outlook.com",
+  "hotmail.com",
+  "live.com",
+  "yahoo.com",
+  "icloud.com",
+  "me.com",
+  "mac.com",
+  "protonmail.com",
+  "proton.me",
+  "fastmail.com",
+  "hey.com",
+  "aol.com",
+  "zoho.com",
+  "yandex.com",
+  "mail.com",
+]);
+
+const AbstractApiResponse = z.object({
+  deliverability: z.enum(["DELIVERABLE", "UNDELIVERABLE", "RISKY", "UNKNOWN"]),
+});
+
+export function isDisposableEmail(email: string): boolean {
+  const domain = email.split("@")[1]?.toLowerCase();
+  if (!domain) {
+    return false;
+  }
+  return disposableSet.has(domain);
+}
+
+async function checkEmailDeliverability(
+  email: string
+): Promise<ValidationResult> {
+  // Dynamic import: Bun's mock.module does not intercept @/ path aliases in
+  // transitive dynamic imports, so the test preload sets process.env fallbacks
+  // to keep the real env.ts from failing when loaded outside the mock scope.
+  const { env } = await import("@/env");
+  const apiKey = env.ABSTRACT_API_KEY;
+  const domain = email.split("@")[1]?.toLowerCase();
+
+  if (!apiKey) {
+    log.warn(
+      "ABSTRACT_API_KEY is not configured — email deliverability checks are disabled"
+    );
+    return { valid: true };
+  }
+
+  if (!domain || TRUSTED_DOMAINS.has(domain)) {
+    return { valid: true };
+  }
+
+  try {
+    const response = await fetch(
+      `https://emailvalidation.abstractapi.com/v1/?api_key=${apiKey}&email=${encodeURIComponent(email)}`,
+      { signal: AbortSignal.timeout(5000) }
+    );
+
+    if (!response.ok) {
+      log.error(
+        `Email deliverability API returned HTTP ${response.status} for domain "${domain}". Failing open.`
+      );
+      return { valid: true };
+    }
+
+    const raw = await response.json();
+    const parsed = AbstractApiResponse.safeParse(raw);
+
+    if (!parsed.success) {
+      log.error(
+        `Unexpected Abstract API response shape for domain "${domain}": ${JSON.stringify(raw)}`
+      );
+      return { valid: true };
+    }
+
+    if (parsed.data.deliverability === "UNDELIVERABLE") {
+      return { valid: false, reason: "undeliverable" };
+    }
+
+    return { valid: true };
+  } catch (error) {
+    if (error instanceof DOMException && error.name === "TimeoutError") {
+      log.warn(
+        `Email deliverability check timed out for domain "${domain}". Failing open.`
+      );
+    } else {
+      log.error(
+        `Email deliverability check failed for domain "${domain}": ${error instanceof Error ? error.message : String(error)}`
+      );
+    }
+    return { valid: true };
+  }
+}
+
+export async function validateEmail(email: string): Promise<ValidationResult> {
+  if (
+    !email ||
+    typeof email !== "string" ||
+    email.length > 254 ||
+    !EMAIL_RE.test(email)
+  ) {
+    return { valid: false, reason: "invalid_format" };
+  }
+
+  if (isDisposableEmail(email)) {
+    return { valid: false, reason: "disposable" };
+  }
+
+  return await checkEmailDeliverability(email);
+}
